// 场景：同时查用户信息 + 订单列表 + 积分余额
public UserDashboard getDashboard(Long userId) {
    CompletableFuture<User> userFuture = CompletableFuture
        .supplyAsync(() -> userMapper.selectById(userId));

    CompletableFuture<List<Order>> orderFuture = CompletableFuture
        .supplyAsync(() -> orderMapper.selectByUserId(userId));

    CompletableFuture<Integer> pointFuture = CompletableFuture
        .supplyAsync(() -> pointService.getBalance(userId));

    // 等待所有完成
    CompletableFuture<Void> all = CompletableFuture.allOf(
        userFuture, orderFuture, pointFuture
    );

    return all.thenApply(v -> {
        User user = userFuture.join();      // join 直接抛异常
        List<Order> orders = orderFuture.join();
        Integer points = pointFuture.join();
        return new UserDashboard(user, orders, points);
    }).join();
}

// 带超时版本
public UserDashboard getDashboardTimeout(Long userId) {
    CompletableFuture<User> userFuture = CompletableFuture
        .supplyAsync(() -> userMapper.selectById(userId))
        .orTimeout(3, TimeUnit.SECONDS);  // 3 秒超时
    // ...
    try {
        return all.get(5, TimeUnit.SECONDS);
    } catch (TimeoutException e) {
        // 降级：返回缓存数据
        return cache.get(userId);
    }
}

// 任意一个完成就返回
public String fastestResponse() {
    return CompletableFuture.anyOf(
        CompletableFuture.supplyAsync(() -> callApiA()),
        CompletableFuture.supplyAsync(() -> callApiB())
    ).thenApply(Object::toString).join();
}
```
注意：必须用自定义线程池，`supplyAsync()` 默认用 ForkJoinPool.commonPool()，多个异步任务会互相抢占。

