public class AlternatePrint {
    private int num = 1;
    private final Object lock = new Object();

    public void printOdd() {
        synchronized (lock) {
            while (num <= 100) {
                while (num % 2 == 0) {
                    lock.wait();  // 偶数时等待
                }
                if (num > 100) break;
                System.out.println("奇数线程: " + num++);
                lock.notify();
            }
        }
    }

    public void printEven() {
        synchronized (lock) {
            while (num <= 100) {
                while (num % 2 == 1) {
                    lock.wait();  // 奇数时等待
                }
                if (num > 100) break;
                System.out.println("偶数线程: " + num++);
                lock.notify();
            }
        }
    }

    public static void main(String[] args) {
        AlternatePrint ap = new AlternatePrint();
        new Thread(ap::printOdd).start();
        new Thread(ap::printEven).start();
    }
}

