// 方案一：AtomicLong（推荐，最常用）
public class Counter {
    private final AtomicLong count = new AtomicLong(0);

    public long increment() { return count.incrementAndGet(); }
    public long get() { return count.get(); }
}

// 方案二：LongAdder（高并发，比 AtomicLong 更快）
public class HighConcurrencyCounter {
    private final LongAdder count = new LongAdder();

    public void increment() { count.increment(); }
    public long get() { return count.sum(); }
}

// 方案三：分段计数器（极致性能，自己实现）
public class StripedCounter {
    private final AtomicLong[] counters;

    public StripedCounter(int stripes) {
        counters = new AtomicLong[stripes];
        for (int i = 0; i < stripes; i++) {
            counters[i] = new AtomicLong();
        }
    }

    public void increment() {
        int idx = Thread.currentThread().hashCode() % counters.length;
        counters[Math.abs(idx)].incrementAndGet();
    }

    public long get() {
        return Arrays.stream(counters).mapToLong(AtomicLong::get).sum();
    }
}
